import * as React from 'react'
import isObject from 'lodash/isObject'
import isArray from 'lodash/isArray'
import { createAPI } from '@airiot/client'
import { Card, CardContent } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { ChevronDown, ChevronUp } from 'lucide-react'
import { fieldRender } from '@/registry/lib/form-relate-utils'

export interface FormRelatePlusDataShowProps {
  relateSchema: {
    showType?: 'select' | 'card' | 'table'
    relateShowFields?: Array<{
      key: string
      title: string
      fieldSchema?: any
    }>
    showField?: string
    relate?: {
      id?: string
    }
    relateTo?: string
  } & Record<string, any>
  input?: {
    value?: any
  }
  field?: {
    displayField?: string
    relateShowFields?: Array<{
      key: string
      title: string
      fieldSchema?: any
    }>
  }
  schema?: {
    name?: string
  }
  val?: any
}

// Parse JSON strings in nested data
function parseJsonStrings(data: any): any {
  if (!data) return data

  const processValue = (value: any): any => {
    if (typeof value === 'string') {
      try {
        const parsed = JSON.parse(value)
        if (typeof parsed === 'object' && parsed !== null) {
          return processValue(parsed)
        }
        return value
      } catch {
        return value
      }
    }

    if (isArray(value)) {
      return value.map(item => processValue(item))
    }

    if (isObject(value)) {
      Object.keys(value).forEach(key => {
        ; (value as Record<string, any>)[key] = processValue((value as Record<string, any>)[key])
      })
      return value
    }

    return value
  }

  return processValue(JSON.parse(JSON.stringify(data)))
}

// Single item display in card format
const ItemShow: React.FC<{
  relateSchema: FormRelatePlusDataShowProps['relateSchema']
  val: object
  field?: FormRelatePlusDataShowProps['field']
  detailPage?: boolean
  relateTableData?: Array<Object>
}> = ({ relateSchema, val, field, detailPage, relateTableData }) => {
  const displayField = field?.displayField || relateSchema.showField || 'name'
  const showFields = relateSchema.relateShowFields || []

  const value = { ...val || {}, ...(relateTableData?.find(item => item.id === val.id) || {}) }

  if (detailPage) {
    return (
      <Card className="inline-block w-[500px] mr-[5px] mt-[5px] bg-muted/50 rounded-md">
        <CardContent className="p-4">
          <div className="grid grid-cols-[5fr_19fr] gap-2 text-sm">
            <div className="text-muted-foreground">记录编号：</div>
            <div>{value.id}</div>
            {showFields.map((f) => (
              <React.Fragment key={f.key}>
                <div className="text-muted-foreground">{f.title}：</div>
                <div>
                  {fieldRender(value[f.key], f.fieldSchema)}
                </div>
              </React.Fragment>
            ))}
          </div>
        </CardContent>
      </Card>
    )
  }

  if (showFields.length > 0) {
    return (
      <Card className="inline-block w-[calc(50%-5px)] mr-[5px] mt-[5px] bg-muted/50 rounded-md">
        <CardContent className="p-3">
          <div className="mb-2">{value[displayField]}</div>
          {showFields.map((f) => (
            <div key={f.key} className="text-xs text-muted-foreground grid grid-cols-[auto_1fr] gap-x-2 gap-y-1">
              <span className="whitespace-nowrap">{f.title}：</span>
              <span className="break-all">
                {fieldRender(value[f.key], f.fieldSchema)}
              </span>
            </div>
          ))}
        </CardContent>
      </Card>
    )
  }

  return (
    <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-secondary text-secondary-foreground mr-1 mt-1">
      {value[displayField]}
    </span>
  )
}

// Table display format
const TableShow: React.FC<FormRelatePlusDataShowProps> = (props) => {
  const { relateSchema, field, val } = props
  const tableID = relateSchema?.relate?.id

  const [loading, setLoading] = React.useState(true)
  const [tableSchema, setTableSchema] = React.useState<any>(null)

  React.useEffect(() => {
    if (tableID) {
      const schemaAPI = createAPI({
        resource: 'core/t/schema',
        name: 'schema'
      })

      schemaAPI.get(tableID)
        .then(({ schema }: any) => {
          setTableSchema(schema)
          setLoading(false)
        })
        .catch(() => {
          setLoading(false)
        })
    } else {
      setLoading(false)
    }
  }, [tableID])

  if (loading) {
    return (
      <div className="flex items-center justify-center py-4">
        <div className="text-sm text-muted-foreground">加载中...</div>
      </div>
    )
  }

  if (!tableSchema) {
    return null
  }

  if (!tableSchema?.fields?.length) {
    return <div className="text-sm text-muted-foreground py-2">请从右侧属性配置中选择显示字段</div>
  }

  const displayField = field?.displayField || relateSchema.showField || 'name'
  const showFields = field?.relateShowFields || relateSchema.relateShowFields || []
  const columns = [displayField, relateSchema.showField, ...showFields.map((f: any) => f.key)]
    .filter(Boolean)

  return (
    <div className="w-full mt-2">
      <div className="border rounded-md">
        <table className="w-full text-sm">
          <thead className="bg-muted/50">
            <tr>
              {columns.map((col: string) => (
                <th key={col} className="px-3 py-2 text-left font-medium">
                  {col}
                </th>
              ))}
            </tr>
          </thead>
          <tbody>
            {val?.map((item: any, index: number) => (
              <tr key={item.id || index} className="border-t">
                {columns.map((col: string) => (
                  <td key={col} className="px-3 py-2">
                    {fieldRender(item[col], tableSchema.fields.find((f: any) => f.key === col))}
                  </td>
                ))}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  )
}

// Main DataShow component
const FormRelatePlusDataShow: React.FC<FormRelatePlusDataShowProps> = (props) => {
  const { relateSchema, input } = props

  const [relateTableData, setRelateTableData] = React.useState<Array<Object>>(null)
  const [loading, setLoading] = React.useState(true)

  React.useEffect(() => { // 关联关联字段时后端只有ID，前端需要请求一次数据才能展示
    const rsf = relateSchema?.relateShowFields || []
    const relateFields = rsf.filter((f: any) => f.fieldSchema?.config === '关联字段')
    if (relateFields.length > 0) {
      const api = createAPI({ resource: relateSchema.name })

      // 使用 api.query 查询数据
      const relateFieldKeys = relateFields?.map((f: { key: string }) => f.key) || []
      api.query(
        {
          limit: 99999,
          fields: ['id', ...relateFieldKeys].filter(Boolean)
        }
      ).then(({ items }: any) => {
        setRelateTableData(items)
      }).finally(() => {
        setLoading(false)
      })
    } else {
      setLoading(false)
    }
  })

  const [expand, setExpand] = React.useState(false)

  if (relateSchema.showType === 'select') {
    return null
  }

  if (loading) {
    return (
      <div className="flex items-center justify-center py-4">
        <div className="text-sm text-muted-foreground">加载中...</div>
      </div>
    )
  }

  if (relateSchema.showType === 'card') {
    const value = input?.value
    const parsedValue = parseJsonStrings(value)

    if (isArray(parsedValue)) {
      const items = parsedValue.length > 6 && !expand ? parsedValue.slice(0, 6) : parsedValue

      return (
        <div className="mt-2 space-y-1">
          {items?.map((v) => (
            <ItemShow key={v.id} {...props} val={v} relateTableData={relateTableData} />
          ))}
          {parsedValue?.length > 6 && !expand && (
            <Button
              type="button"
              variant="link"
              size="sm"
              onClick={() => setExpand(true)}
              className="text-primary"
            >
              展开更多（共{parsedValue.length}条）
              <ChevronDown className="h-4 w-4 ml-1" />
            </Button>
          )}
          {parsedValue?.length > 6 && expand && (
            <Button
              type="button"
              variant="link"
              size="sm"
              onClick={() => setExpand(false)}
              className="text-primary"
            >
              收起（共{parsedValue.length}条）
              <ChevronUp className="h-4 w-4 ml-1" />
            </Button>
          )}
        </div>
      )
    }

    if (parsedValue) {
      return (
        <div className="mt-2">
          <ItemShow {...props} val={parsedValue} relateTableData={relateTableData} />
        </div>
      )
    }

    return null
  }

  if (relateSchema.showType === 'table') {
    return <TableShow {...props} val={parseJsonStrings(input?.value)} />
  }

  return null
}

export { FormRelatePlusDataShow }
export default FormRelatePlusDataShow

import isEmpty from 'lodash/isEmpty'
import isObject from 'lodash/isObject'
import isArray from 'lodash/isArray'
import { getQueryFilter } from './filter-utils'

/**
 * 在 tableSchema 中查找 value?.relate?.id 等于 tableID 的对应 key
 */
export const findRelateKeyInTableSchema = (tableSchema: any, tableID: string): string | null => {
  if (!tableSchema || !tableSchema.properties) {
    return null
  }

  for (const [key, property] of Object.entries(tableSchema.properties)) {
    if ((property as any)?.relate?.id === tableID) {
      return key
    }
  }

  return null
}

/**
 * 在树形数据中查找节点
 */
export const findTreeNode = (treeData: any[], value: any): any => {
  for (const node of treeData) {
    if (node.value === value) {
      return node
    }
    if (node.children && node.children.length > 0) {
      const found = findTreeNode(node.children, value)
      if (found) return found
    }
  }
  return null
}

/**
 * 替换字段占位符
 * 将 [field]:fieldName 或 [field][table]:fieldName 替换为实际值
 */
export const replaceFieldPlaceholders = (value: any, allValues: Record<string, any>): any => {
  if (typeof value === 'string') {
    // 处理 [field]:fieldName 占位符
    if (value.startsWith('[field]:')) {
      const key = value.substring(8)
      return allValues[key] !== undefined ? allValues[key] : value
    }
    // 处理 [field][table]:fieldName 占位符
    if (value.startsWith('[field][table]:')) {
      const key = value.substring(15)
      return allValues[key] !== undefined ? allValues[key] : value
    }
    return value
  }

  if (isArray(value)) {
    return value.map(item => replaceFieldPlaceholders(item, allValues))
  }

  if (isObject(value) && value !== null) {
    const result: Record<string, any> = {}
    for (const [key, val] of Object.entries(value)) {
      result[key] = replaceFieldPlaceholders(val, allValues)
    }
    return result
  }

  return value
}

/**
 * 处理过滤器
 * 将内置查询过滤器应用到 filterObj 中
 *
 * @param filterObj - 过滤器对象，会被修改
 * @param field - 字段配置
 * @param getFormState - 获取表单状态的函数
 * @param outTable - 外部表的 editingSchema（可选）
 */
export const dealFilter = (
  filterObj: Record<string, any>,
  field: any,
  getFormState?: () => any,
  outTable?: { editingSchema?: Record<string, any> }
) => {
  // 在过滤器中，如果没有设置 field.filter，则使用内置查询
  const ifFilter = field.filter

  // 设置了内置查询
  if (field.insideFilter && !ifFilter) {
    const inFilter = getQueryFilter(field.insideFilter, field.schema)
    const allValues = {
      ...(outTable?.editingSchema || {}),
      ...(getFormState?.()?.values || {})
    }

    // 确保 filterObj 有 search 属性
    if (!filterObj.search) {
      filterObj.search = {}
    }

    // 替换占位符并添加到搜索条件中
    for (const key in inFilter) {
      let insideVal = inFilter[key]
      const replacedVal = replaceFieldPlaceholders(insideVal, allValues)
      filterObj.search[key] = replacedVal
    }
  }
}

/**
 * 简单的 fieldRender 函数
 * 用于在列表中显示字段值
 */
export const fieldRender = (value: any, _schema?: any): React.ReactNode => {
  // 字符串、数字、布尔值直接显示
  if (typeof value === 'string' || typeof value === 'number' || typeof value === 'boolean') {
    return value
  }

  // 对象显示 .name
  if (isObject(value) && !isArray(value)) {
    return (value as any).name ?? (value as any).id ?? JSON.stringify(value)
  }

  // 数组显示 .name join(',')
  if (isArray(value)) {
    return value
      .map(item => {
        if (typeof item === 'string' || typeof item === 'number') {
          return item
        }
        if (isObject(item)) {
          return (item as any).name ?? (item as any).id
        }
        return JSON.stringify(item)
      })
      .filter(Boolean)
      .join(',')
  }

  // 空值处理
  if (isEmpty(value)) {
    return null
  }

  return JSON.stringify(value)
}

/**
 * 获取表单状态 - 用于获取其他字段的值
 * 类似于 use('form') 的功能
 */
export const getFormState = (formState: any, currentFieldKey?: string) => {
  // TODO: 实现表单状态获取逻辑
  // 这个函数应该从 form state 中获取其他字段的值
  // 用于字段联动和脚本计算
  if (!formState) {
    return {}
  }

  const values: Record<string, any> = {}
  for (const key in formState.values) {
    // 跳过当前字段，避免循环依赖
    if (key !== currentFieldKey) {
      values[key] = formState.values[key]
    }
  }

  return { values }
}

/**
 * 获取表单所有值 - 用于字段脚本
 */
export const getFormValues = (schema: any, formState?: any) => {
  if (!formState) {
    return null
  }

  const values: Record<string, any> = {}
  for (const key in formState.values) {
    if (key !== schema.key) {
      values[key] = formState.values[key]
    }
  }

  return values
}
